/* PasstheEPPP — Question Bank Batch 39
   85 new questions across all 8 domains — Ethics, Clinical, Assessment, Treatment focus */
(function(){
    if (typeof EPPPData === 'undefined') return;

    const batch39 = [
        // ===== Domain 8: Ethics (15) =====
        {domainId:8, q:"A psychologist's client reveals plans to harm a specific coworker. The psychologist should FIRST:", options:["Wait passively to see if the client acts on the stated threat over time","Assess the seriousness and imminence of the threat to the coworker","Immediately call local police to intervene and prevent potential harm","Terminate therapy immediately to avoid professional liability risks"], answer:1, difficulty:"medium", rationale:"Correct: (B) Before taking protective action, the psychologist must assess the credibility, specificity, and imminence of the threat. Tarasoff requires action for serious, credible threats to identifiable victims — but clinical assessment comes first to determine if the threshold is met.\n\nWhy others are wrong:\n(A) Waiting passively could be negligent if the threat is serious\n(C) Calling police may be warranted but only after assessing the threat — premature action violates client trust unnecessarily\n(D) Termination doesn't address the safety concern"},
        {domainId:8, q:"A psychologist is asked to provide therapy to their doctoral student's spouse. This situation:", options:["Is entirely acceptable as long as the student provides formal written consent","Creates a problematic multiple relationship that should generally be avoided","Is only ethically problematic if the therapeutic intervention yields poor results","Is always universally acceptable provided both parties are consulting adults"], answer:1, difficulty:"medium", rationale:"Correct: (B) Treating a supervisee's/student's spouse creates overlapping relationships that could impair objectivity, compromise the supervisory relationship, or create conflicts of interest. APA Standard 3.05 advises avoiding such situations.\n\nWhy others are wrong:\n(A) Consent doesn't eliminate the structural power dynamics\n(C) Ethical issues exist regardless of outcome\n(D) The professional power differential makes this problematic regardless of consent"},
        {domainId:8, q:"Under HIPAA, a 'covered entity' includes:", options:["Only inpatient hospital settings and acute medical care treatment facilities","Health plans, health care clearinghouses, and electronic healthcare providers","Any general business organization that officially employs medical personnel","Only government-funded agencies providing direct patient care services"], answer:1, difficulty:"medium", rationale:"Correct: (B) HIPAA covered entities include health plans, health care clearinghouses, and providers who conduct certain electronic transactions. Psychologists in private practice who bill electronically are covered entities.\n\nWhy others are wrong:\n(A) Hospitals are included but are not the only covered entities\n(C) General businesses are not covered entities unless they meet the criteria\n(D) HIPAA applies to private entities, not just government"},
        {domainId:8, q:"A client asks their psychologist to write a letter supporting their disability claim. The psychologist should:", options:["Refuse completely because providing such letters is outside the scope of practice","Write whatever the client specifically requests to maintain the therapeutic alliance","Provide objective clinical information within competence, stating opinion basis clearly","Mandatorily refer the client to a board-certified forensic psychologist in all cases"], answer:2, difficulty:"medium", rationale:"Correct: (C) Psychologists can provide factual clinical information (diagnosis, functional limitations, treatment history) based on their direct knowledge. They should state the basis for opinions and avoid advocating beyond their data.\n\nWhy others are wrong:\n(A) Providing clinical documentation is within the scope of practice\n(B) Writing whatever the client wants compromises integrity\n(D) Referral may be appropriate for complex forensic evaluations but is not always required for clinical letters"},
        {domainId:8, q:"The APA Ethics Code Standard 9.01 states that psychological assessments should be:", options:["Based on a single comprehensive testing instrument whenever clinically possible","Based on information and techniques sufficient to substantiate derived findings","Conducted strictly by independently licensed psychologists without trainee involvement","Standardized exclusively on the exact demographic population being currently tested"], answer:1, difficulty:"easy", rationale:"Correct: (B) Standard 9.01 requires that opinions be based on sufficient information, using appropriate assessment methods. Multi-method assessment increases validity.\n\nWhy others are wrong:\n(A) Relying on a single test violates the multi-method principle\n(C) Supervised trainees can conduct assessments under appropriate supervision\n(D) While normative data should be appropriate, exact population match is not always possible"},
        {domainId:8, q:"A psychologist practicing in a rural community discovers their only grocery store clerk is also their client. This situation is BEST described as:", options:["A severe boundary violation requiring immediate clinical termination and referral","An unavoidable multiple relationship requiring careful therapeutic boundary management","A compelling professional reason to immediately relocate the psychological practice","Acceptable without any intervention only if the store clerk provides verbal consent"], answer:1, difficulty:"easy", rationale:"Correct: (B) In rural/small communities, some multiple relationships are unavoidable. APA Standard 3.05(c) acknowledges this and requires psychologists to take reasonable steps to manage boundary issues rather than simply avoiding all contact.\n\nWhy others are wrong:\n(A) Not all multiple relationships are violations — context matters\n(C) Relocating is unreasonable and impractical\n(D) While discussion is important, the key is management of the boundary"},
        {domainId:8, q:"A psychologist suspects their elderly client is being financially exploited by a family member. In most states, the psychologist:", options:["Has absolutely no mandatory reporting obligation for cognitively intact adult clients","Is a mandated reporter for elder abuse and must report the suspected exploitation","Should unilaterally report the situation only if the elderly client explicitly requests it","Must first obtain the client's formal written consent before filing any official report"], answer:1, difficulty:"medium", rationale:"Correct: (B) Most states include psychologists as mandated reporters for elder abuse, including financial exploitation. Like child abuse reporting, suspected abuse must be reported regardless of client consent.\n\nWhy others are wrong:\n(A) Most states mandate elder abuse reporting\n(C) Mandated reporting doesn't require client request\n(D) Mandated reporting overrides confidentiality — consent is not required"},
        {domainId:8, q:"Psychologists who provide supervision have an ethical obligation to:", options:["Allow supervisees to exercise complete autonomy in all independent clinical decisions","Monitor the quality of supervisee work and provide ongoing constructive feedback","Only review client cases when the assigned supervisee specifically requests consultation","Delegate all ultimate responsibility to the supervisee once they attain full licensure"], answer:1, difficulty:"easy", rationale:"Correct: (B) APA Standard 7.06 requires supervisors to establish timely, specific feedback processes and to take reasonable steps to ensure competent performance. Supervisors retain ultimate responsibility for client welfare.\n\nWhy others are wrong:\n(A) Complete autonomy without oversight is negligent supervision\n(C) Passive supervision fails to meet gatekeeping responsibilities\n(D) Supervisors maintain responsibility throughout the supervisory relationship"},
        {domainId:8, q:"When a psychologist disagrees with a court order to release client records, the BEST course of action is to:", options:["Completely ignore the court order to protect the client's uncompromised confidentiality","Comply with the court order while taking steps to limit disclosure to what is necessary","Immediately destroy all clinical records to successfully prevent any forced legal disclosure","Flatly refuse to comply and accept the inevitable risk of enduring contempt of court charges"], answer:1, difficulty:"hard", rationale:"Correct: (B) Unlike a subpoena, a court order must be obeyed. However, the psychologist can request in camera review (judge reviews records privately), redaction of irrelevant material, or a protective order to limit disclosure.\n\nWhy others are wrong:\n(A) Ignoring a court order can result in contempt charges\n(C) Destroying records is illegal and unethical (obstruction)\n(D) Refusing a valid court order results in contempt without protecting the client"},
        {domainId:8, q:"The ethical principle of Justice in the APA Ethics Code refers to:", options:["Ensuring all distinct clients systematically receive procedurally identical clinical treatment","Fairness and equal access to the benefits of established psychological contributions","Following all applicable state laws and federal statutes without any allowable exception","Punishing unethical colleagues through formal organizational disciplinary procedures"], answer:1, difficulty:"easy", rationale:"Correct: (B) Principle D (Justice) addresses fairness, equality, and ensuring all persons have access to and benefit from psychology. It recognizes potential biases and promotes equitable treatment.\n\nWhy others are wrong:\n(A) Justice doesn't mean identical treatment — it means equitable treatment appropriate to individual needs\n(C) Justice is broader than legal compliance\n(D) Justice is about fairness and access, not punishment"},
        {domainId:8, q:"A psychologist receives a referral for a client whose presenting problem is outside their area of competence. The psychologist should:", options:["Accept the client unconditionally and attempt to learn necessary skills as treatment progresses","Decline the complex referral entirely and successfully refer the patient to a qualified colleague","Accept only if no other providers exist, proceeding with appropriate consultation and disclosure","Either formally decline and refer to a colleague, or treat with adequate consultation if necessary"], answer:3, difficulty:"medium", rationale:"Correct: (D) Ideally, refer to a qualified colleague (B). However, if no qualified provider is available (e.g., rural area), accepting with appropriate study, consultation, supervision, and informed disclosure to the client may be ethical (APA Standard 2.01).\n\nWhy others are wrong:\n(A) 'Learning as you go' without safeguards violates competence standards\n(B) This is the ideal but not the only ethical option\n(C) This is appropriate but only when B is not feasible"},
        {domainId:8, q:"PSYPACT (Psychology Interjurisdictional Compact) allows psychologists to:", options:["Practice in any U.S. state without encountering any additional regulatory requirements","Practice telepsychology across participating PSYPACT states without individual state licensure","Ignore specific state-level legislative laws governing traditional psychological practice and ethics","Supervise trainees seamlessly across any state jurisdiction without regard for local regulations"], answer:1, difficulty:"medium", rationale:"Correct: (B) PSYPACT allows licensed psychologists in participating states to provide telepsychology services to clients in other PSYPACT states without obtaining individual state licenses. It requires an E.Passport or IPC.\n\nWhy others are wrong:\n(A) PSYPACT has specific requirements and only applies to participating states\n(C) State-specific laws still apply regarding practice standards\n(D) PSYPACT primarily covers telepsychology and temporary in-person practice, with specific rules for supervision"},
        {domainId:8, q:"When using psychological tests with culturally diverse clients, the psychologist MUST:", options:["Only utilize specialized testing instruments properly normed on the client's specific cultural group","Consider the test's limitations for the specific population and interpret results with cultural context","Avoid objective testing altogether to effectively prevent culturally biased clinical misinterpretation","Use only subjective projective assessment instruments which are inherently culturally universally fair"], answer:1, difficulty:"medium", rationale:"Correct: (B) APA Standard 9.06 requires psychologists to consider the purpose, norms, reliability, validity, and limitations of tests when used with populations not represented in the standardization sample. Cultural context must inform interpretation.\n\nWhy others are wrong:\n(A) Tests normed on every specific group often don't exist — the key is thoughtful interpretation\n(C) Avoiding testing entirely deprives clients of potentially useful assessment\n(D) Projective tests are not inherently more 'culture-fair'"},
        {domainId:8, q:"A psychologist discovers a billing error that resulted in overcharging a client for 6 months. Ethically, the psychologist should:", options:["Do absolutely nothing assuming the client has not explicitly noticed the financial administration discrepancy","Immediately inform the client of the error, correct the ongoing billing, and promptly issue a full refund","Wait comfortably until the scheduled termination of treatment to address the historical billing mistake","Only officially correct the mistake and issue compensation if the client proactively asks for an explanation"], answer:1, difficulty:"easy", rationale:"Correct: (B) APA Principle C (Integrity) and Standard 6.04 require honest fee practices. Discovering an error obligates the psychologist to promptly disclose it, correct it, and refund the overcharge.\n\nWhy others are wrong:\n(A) Concealing a billing error violates integrity\n(C) Delaying disclosure is dishonest\n(D) Waiting for the client to notice is passive deception"},
        {domainId:8, q:"A psychologist's personal values conflict with a client's lifestyle. The psychologist should:", options:["Refuse unequivocally to treat the controversial client based solely on the cited incompatible personal values","Attempt persistently to change the client's lifestyle to effectively match the psychologist's ethical values","Provide competent services without imposing personal values, or arrange an appropriate referral if unable","Disclose their explicit personal disapproval strictly to remain completely 'authentic' in the therapeutic space"], answer:2, difficulty:"easy", rationale:"Correct: (C) APA Principle E (Respect for Rights and Dignity) requires psychologists to respect differences. If personal values prevent competent service, ethical referral is appropriate — but the psychologist should not impose their values.\n\nWhy others are wrong:\n(A) Refusing service solely based on personal values may constitute discrimination\n(B) Imposing values violates client autonomy and Principle E\n(D) Disclosing disapproval could harm the therapeutic relationship and constitutes imposing values"},

        // ===== Domain 5: Assessment (15) =====
        {domainId:5, q:"A patient obtains a Full Scale IQ of 100 on the WAIS-IV with a Working Memory Index of 75. This pattern suggests:", options:["Completely normal cognitive functioning across all assessed intellectual domains","A specific weakness in working memory despite average overall cognitive ability","The test results are statistically invalid and should not be clinically interpreted","Intellectual disability requiring immediate adaptive behavior functioning assessment"], answer:1, difficulty:"medium", rationale:"Correct: (B) A 25-point discrepancy between FSIQ (100) and WMI (75) represents a significant intra-individual difference, suggesting a specific weakness in working memory that may impact academic/occupational functioning despite average overall cognitive ability.\n\nWhy others are wrong:\n(A) The significant index discrepancy indicates uneven functioning\n(C) Score discrepancies don't automatically invalidate results\n(D) FSIQ of 100 is average — not in the ID range"},
        {domainId:5, q:"The MCMI-IV is specifically designed to align with:", options:["The World Health Organization's ICD-11 diagnostic classifications and categories","DSM-5 personality disorders and corresponding major clinical syndrome constructs","Neuropsychological constructs measuring executive functioning and memory domains","Educational achievement categories utilized in specific learning disorder diagnosis"], answer:1, difficulty:"easy", rationale:"Correct: (B) The Millon Clinical Multiaxial Inventory was specifically designed to align with DSM personality disorder constructs and clinical syndromes (Millon's evolutionary model of personality).\n\nWhy others are wrong:\n(A) The MCMI aligns with DSM, though there is overlap with ICD\n(C) It's a personality/clinical instrument, not neuropsychological\n(D) It assesses clinical/personality constructs, not educational achievement"},
        {domainId:5, q:"In signal detection theory applied to diagnostic testing, a 'hit' refers to:", options:["A false positive where the condition is diagnosed but is not actually present","Correctly identifying someone who has the condition representing a true positive","Correctly identifying someone who does not have the condition (true negative)","A miss where the condition is present but the diagnostic test fails to detect it"], answer:1, difficulty:"medium", rationale:"Correct: (B) Signal detection: Hit = true positive (correctly detecting the 'signal'/condition). Miss = false negative. False alarm = false positive. Correct rejection = true negative.\n\nWhy others are wrong:\n(A) False positive = false alarm in signal detection\n(C) Correctly identifying absence = correct rejection\n(D) A miss is a false negative — failing to detect a present signal"},
        {domainId:5, q:"The Halstead-Reitan Battery is PRIMARILY used for:", options:["Objective multidimensional personality assessment and psychopathology screening","Comprehensive neuropsychological evaluation of brain-behavior relationships","Rapid screening for symptoms of major depressive disorder in primary care","Standardized intelligence testing across the full lifespan developmental trajectory"], answer:1, difficulty:"easy", rationale:"Correct: (B) The Halstead-Reitan is a comprehensive neuropsychological battery assessing motor function, sensory-perceptual, attention, language, visual-spatial, and executive functioning. It can help localize brain damage and assess severity.\n\nWhy others are wrong:\n(A) Personality → MMPI, MCMI, Rorschach\n(C) Depression screening → BDI, PHQ-9\n(D) Intelligence → WAIS, WISC"},
        {domainId:5, q:"Regression to the mean is MOST likely to affect:", options:["All test scores uniformly regardless of their initial measurement baseline value","Extreme scores on initial testing which tend to be more moderate on retesting","Scores falling exactly at the median which systematically drift over test epochs","Scores exclusively obtained from highly reliable standardized psychometric tests"], answer:1, difficulty:"medium", rationale:"Correct: (B) Regression to the mean: extreme scores (very high or very low) tend to move toward the mean on retesting due to measurement error. The more extreme the initial score and the lower the test reliability, the greater the expected regression.\n\nWhy others are wrong:\n(A) Average scores show minimal regression\n(C) Median scores are already near the mean — minimal regression\n(D) Regression occurs with ALL tests but is MORE pronounced with less reliable tests"},
        {domainId:5, q:"Discriminant validity is demonstrated when a test:", options:["Correlates highly with well-established measures of the exact same construct","Shows low correlation with established measures of theoretically distinct constructs","Accurately successfully predicts future behavioral performance on a relevant criterion","Demonstrates exceptionally high internal consistency reliability across all test items"], answer:1, difficulty:"medium", rationale:"Correct: (B) Discriminant (divergent) validity: a test should NOT correlate strongly with measures of unrelated constructs. An anxiety scale should correlate highly with other anxiety measures (convergent) but weakly with, say, extraversion (discriminant).\n\nWhy others are wrong:\n(A) High correlation with same construct = convergent validity\n(C) Predicting future performance = predictive validity\n(D) Internal consistency = reliability, not validity"},
        {domainId:5, q:"A z-score of -2.0 falls at approximately the:", options:["16th percentile indicating score performance one standard deviation below average","2nd percentile indicating score performance two standard deviations below average","50th percentile indicating score performance exactly at the population distribution mean","84th percentile indicating score performance one standard deviation above the mean"], answer:1, difficulty:"easy", rationale:"Correct: (B) In a normal distribution: z = -2.0 → ~2.3rd percentile (often rounded to 2nd). Key benchmarks: z=-2 ≈ 2nd, z=-1 ≈ 16th, z=0 = 50th, z=+1 ≈ 84th, z=+2 ≈ 98th.\n\nWhy others are wrong:\n(A) 16th percentile = z of -1.0\n(C) 50th percentile = z of 0\n(D) 84th percentile = z of +1.0"},
        {domainId:5, q:"The TOMM (Test of Memory Malingering) is specifically designed to detect:", options:["Genuine memory impairment resulting from documented traumatic brain injury events","Exaggerated or intentionally feigned cognitive deficits and memory dysfunctions","Depression-related memory problems resembling neurocognitive degenerative disorders","Early onset Alzheimer's disease progression tracking over longitudinal timeframes"], answer:1, difficulty:"easy", rationale:"Correct: (B) The TOMM is a symptom validity test using a forced-choice recognition paradigm. Performance significantly below chance indicates intentional wrong answers (malingering), since even genuinely impaired individuals perform above chance on forced-choice tasks.\n\nWhy others are wrong:\n(A) The TOMM detects FAKING, not genuine impairment\n(C) Depression-related memory issues would still produce above-chance performance\n(D) The TOMM is a validity test, not a diagnostic tool for dementia"},
        {domainId:5, q:"When interpreting MMPI-2 results, a 'spike' profile (single clinical scale elevation) most commonly suggests:", options:["Multiple complex comorbid psychiatric conditions occurring simultaneously in the patient","A relatively focal, well-defined clinical presentation without complex comorbidities","Statistically invalid test results requiring re-administration of the entire protocol","Exceptionally severe psychopathology spanning multiple diverse diagnostic categories"], answer:1, difficulty:"hard", rationale:"Correct: (B) A spike profile (one significantly elevated clinical scale with others in normal range) suggests a circumscribed clinical issue. For example, an isolated Scale 2 elevation suggests depression without complex comorbidity.\n\nWhy others are wrong:\n(A) Multiple comorbidities produce multiple scale elevations\n(C) A single elevation doesn't indicate invalidity — check validity scales\n(D) Severity is determined by elevation height, not number of elevations"},
        {domainId:5, q:"Split-half reliability assesses:", options:["Test-retest temporal stability across multiple sequential assessment administrations","Internal consistency by statistically correlating two halves of a single instrument","Diagnostic agreement between different independent clinical raters evaluating clients","Whether the test accurately measures the underlying theoretical construct it claims to"], answer:1, difficulty:"easy", rationale:"Correct: (B) Split-half reliability divides the test into two halves (e.g., odd/even items), correlates them, and applies the Spearman-Brown formula to estimate full-test reliability. It's a measure of internal consistency.\n\nWhy others are wrong:\n(A) Test-retest = temporal stability\n(C) Agreement between raters = inter-rater reliability\n(D) Measuring what it claims = validity"},
        {domainId:5, q:"Autism Spectrum Disorder in DSM-5 requires deficits in:", options:["Only qualitative aspects of social communication and reciprocal interpersonal interaction","Only restricted, repetitive patterns of behavior, specialized interests, or basic activities","Both social communication deficits AND restricted/repetitive behavioral patterns clearly present","Expressive language delay and marked intellectual cognitive impairment exclusively observed"], answer:2, difficulty:"easy", rationale:"Correct: (C) DSM-5 ASD requires: (1) persistent deficits in social communication/interaction across contexts AND (2) restricted, repetitive patterns of behavior, interests, or activities. Both criteria must be met.\n\nWhy others are wrong:\n(A) Social communication deficits alone = Social Communication Disorder (not ASD)\n(B) RRBs alone are insufficient for ASD diagnosis\n(D) Language delay is no longer a diagnostic criterion in DSM-5 ASD"},
        {domainId:5, q:"Standard scores on the WAIS have a mean of 100 and SD of 15. A score of 130 is:", options:["Precisely one standard deviation above the normative mean representing average ability","Two standard deviations above the normative mean suggesting very superior functioning","Three standard deviations above the normative mean reflecting profound cognitive giftedness","Falling exactly at the 84th percentile ranking within the standardized population distribution"], answer:1, difficulty:"easy", rationale:"Correct: (B) 130 = 100 + 2(15) = 2 SDs above the mean ≈ 98th percentile. This falls in the 'Very Superior' range on the WAIS.\n\nWhy others are wrong:\n(A) 1 SD above = 115\n(C) 3 SDs above = 145\n(D) 84th percentile = 1 SD above (score of 115)"},
        {domainId:5, q:"The Vineland Adaptive Behavior Scales measure:", options:["General intellectual functioning across verbal and nonverbal cognitive performance scales","Adaptive behavior encompassing communication, daily living, socialization, and motor domains","Stable multidimensional personality traits using objective self-report questionnaire formats","Specific academic achievement levels across reading, mathematics, and writing disciplines"], answer:1, difficulty:"easy", rationale:"Correct: (B) The Vineland is a semi-structured interview (or rating form) assessing adaptive behavior across domains: Communication, Daily Living Skills, Socialization, and Motor Skills. Essential for diagnosing intellectual disability — DSM-5 requires adaptive deficits.\n\nWhy others are wrong:\n(A) Intelligence → WAIS/WISC\n(C) Personality → MMPI/MCMI\n(D) Academic achievement → Woodcock-Johnson, WIAT"},
        {domainId:5, q:"A ceiling effect occurs when:", options:["A testing instrument is significantly too conceptually difficult for most evaluated examinees","A test is too easy, preventing meaningful score differentiation among high-performing individuals","Examinee raw scores cluster tightly around the statistical mean creating a normal distribution","The utilized psychometric test simply contains too few assessment items to be highly reliable"], answer:1, difficulty:"medium", rationale:"Correct: (B) Ceiling effect: when a test is too easy, most examinees score at or near the maximum, creating a negatively skewed distribution. This prevents the test from discriminating among high-ability individuals.\n\nWhy others are wrong:\n(A) Test too difficult = floor effect\n(C) Clustering around the mean suggests a normal distribution\n(D) Too few items affects reliability, not necessarily ceiling effects"},
        {domainId:5, q:"In DSM-5, Specific Learning Disorder is diagnosed when:", options:["Overall cognitive intellectual quotient falls significantly below seventy standard score points","There is a significant statistical discrepancy between global IQ and specific academic achievement","Academic skills are substantially below expected, persist despite intervention, and are unexplained otherwise","The child meets full diagnostic criteria for Attention-Deficit/Hyperactivity Disorder simultaneously"], answer:2, difficulty:"medium", rationale:"Correct: (C) DSM-5 SLD criteria: (1) difficulties in reading, writing, or math for ≥6 months despite intervention; (2) substantially below age expectations; (3) begins during school-age years; (4) not better explained by ID, sensory deficits, etc. DSM-5 moved away from the IQ-achievement discrepancy model.\n\nWhy others are wrong:\n(A) IQ below 70 = intellectual disability, not SLD\n(B) DSM-5 no longer requires IQ-achievement discrepancy\n(D) ADHD is a separate diagnosis — though comorbidity is common"},

        // ===== Domain 6: Treatment (15) =====
        {domainId:6, q:"Prolonged Exposure (PE) therapy for PTSD works primarily through:", options:["Cognitive restructuring of maladaptive trauma-related core beliefs and intermediate assumptions","Repeated confrontation with trauma memories and avoided situations until emotional habituation occurs","Medication management specifically targeting autonomic nervous system hyperarousal symptomology","Psychodynamic dream analysis focusing on the symbolic manifestation of repressed traumatic content"], answer:1, difficulty:"medium", rationale:"Correct: (B) PE (Foa) involves imaginal exposure (repeatedly recounting the trauma narrative) and in vivo exposure (gradually approaching avoided trauma-related situations). Emotional processing theory: repeated exposure → habituation → reduction in trauma-related distress.\n\nWhy others are wrong:\n(A) Cognitive restructuring is CPT's primary mechanism — PE focuses on exposure\n(C) PE is a psychotherapy, not pharmacotherapy\n(D) Dream analysis is psychoanalytic, not PE"},
        {domainId:6, q:"In Bowen's family therapy, 'differentiation of self' refers to:", options:["Temporary physical separation from the immediate nuclear family environment","The ability to distinguish between intellectual and emotional functioning while remaining connected","Being persistently emotionally cut off from all primary family of origin relationship dynamics","Participating in intensive individual therapy concurrently within the broader family systems format"], answer:1, difficulty:"medium", rationale:"Correct: (B) Differentiation: the ability to maintain a clear sense of self (balance thinking and feeling) while staying emotionally connected to significant others. Low differentiation = emotional reactivity and fusion with others' emotions.\n\nWhy others are wrong:\n(A) Physical distance ≠ differentiation — one can be geographically distant but emotionally fused\n(C) Emotional cutoff is actually a sign of LOW differentiation\n(D) Differentiation is a developmental construct, not a therapy format"},
        {domainId:6, q:"The primary goal of Interpersonal Therapy (IPT) for depression is:", options:["Systematically identifying and subsequently challenging cognitive distortions underlying depression","Resolving the current interpersonal problems that actively contribute to and maintain the depression","Extensively exploring unconscious neurotic conflicts originating from early childhood experiences","Prescribing and managing appropriate antidepressant medications throughout the acute treatment phase"], answer:1, difficulty:"medium", rationale:"Correct: (B) IPT (Klerman & Weissman) focuses on four interpersonal problem areas: grief/loss, role disputes, role transitions, and interpersonal deficits. Improving interpersonal functioning reduces depressive symptoms. IPT is time-limited (12-16 sessions) and evidence-based for MDD.\n\nWhy others are wrong:\n(A) Cognitive distortions → CBT\n(C) Unconscious conflicts → psychoanalytic therapy\n(D) IPT is psychotherapy, not pharmacotherapy"},
        {domainId:6, q:"Contingency management in substance use treatment involves:", options:["Aggressively challenging irrational beliefs surrounding the initiation and maintenance of substance use","Providing concrete tangible rewards universally contingent upon verified objective evidence of abstinence","Thoroughly processing severe childhood trauma theoretically related to adult substance use behaviors","Intensive group confrontation specifically targeting the client's psychological denial mechanisms"], answer:1, difficulty:"easy", rationale:"Correct: (B) Contingency management uses operant conditioning — providing reinforcement (vouchers, prize draws) contingent on objective evidence of abstinence (urine screens). Strong evidence base for stimulant and opioid use disorders.\n\nWhy others are wrong:\n(A) Challenging beliefs → CBT/REBT\n(C) Exploring childhood trauma → psychodynamic approaches\n(D) Group confrontation → older 'attack therapy' models, now considered harmful"},
        {domainId:6, q:"Narrative therapy (White & Epston) primarily aims to:", options:["Interpret highly symbolic unconscious material retrieved through free association processes","Help clients re-author their stories by carefully separating their core identity from their problems","Conduct systematic desensitization for specific phobic anxiety and related avoidance behaviors","Teach progressive muscle relaxation techniques effectively establishing autonomic nervous system balance"], answer:1, difficulty:"medium", rationale:"Correct: (B) Narrative therapy externalizes problems ('the problem is the problem, not the person') and helps clients identify 'unique outcomes' — exceptions to their dominant problem-saturated narratives — to construct preferred alternative stories.\n\nWhy others are wrong:\n(A) Unconscious interpretation → psychoanalysis\n(C) Systematic desensitization → behavioral therapy\n(D) Relaxation → behavioral/stress management"},
        {domainId:6, q:"Functional analytic psychotherapy (FAP) focuses on:", options:["Extensive psychoanalytic dream interpretation regarding interpersonal relationships","Clinically relevant behavioral patterns that manifest directly within the therapeutic relationship","Strict adherence to prescribed cognitive-behavioral out-of-session homework assignments","Modifying structural family systems dynamics through active therapist directive interventions"], answer:1, difficulty:"hard", rationale:"Correct: (B) FAP (Kohlenberg & Tsai) focuses on client behaviors occurring in-session as real-time examples of interpersonal patterns. CRB1 = problem behaviors in session; CRB2 = improved behaviors; CRB3 = client's interpretations. The therapeutic relationship is the vehicle for change.\n\nWhy others are wrong:\n(A) Dream analysis → psychoanalytic\n(C) FAP specifically focuses on in-session behavior, not homework\n(D) Family systems → Minuchin, Bowen, strategic family therapy"},
        {domainId:6, q:"For Panic Disorder, the MOST effective evidence-based treatment is:", options:["Long-term psychodynamic psychoanalysis examining underlying unconscious conflict","Cognitive-behavioral therapy specifically utilizing systematic interoceptive exposure","Traditional hypnotherapy focused on deeply uncovering repressed traumatic childhood memories","Client-centered play therapy encouraging non-directive emotional self-expression"], answer:1, difficulty:"easy", rationale:"Correct: (B) CBT for panic includes: psychoeducation, cognitive restructuring (catastrophic misinterpretation of bodily sensations), interoceptive exposure (deliberately inducing feared sensations), and in vivo exposure to avoided situations.\n\nWhy others are wrong:\n(A) Psychoanalysis lacks strong evidence for panic disorder\n(C) Hypnotherapy — limited evidence for panic\n(D) Play therapy is for children, not specifically for panic"},
        {domainId:6, q:"Psychoeducation as a therapeutic intervention involves:", options:["Lecturing the non-compliant client severely regarding their various psychological symptom deficiencies","Providing clients and family members with comprehensive information about their clinical condition","Teaching clinical clients to independently function as professional diagnostic psychologists","Simply providing standardized written materials without accompanying therapeutic discussion"], answer:1, difficulty:"easy", rationale:"Correct: (B) Psychoeducation teaches clients/families about the nature of their condition, expected course, treatment options, early warning signs, and coping strategies. It improves treatment adherence, reduces relapse, and empowers clients.\n\nWhy others are wrong:\n(A) Psychoeducation is empowering, not judgmental\n(C) It educates about the condition, not professional training\n(D) It includes discussion, Q&A, and skill-building, not just reading materials"},
        {domainId:6, q:"The 'miracle question' is a technique used in:", options:["Traditional Cognitive-Behavioral Therapy focusing extensively on cognitive restructuring","Classical Psychoanalysis emphasizing the interpretation of unconscious dream symbolism","Solution-Focused Brief Therapy to help clients concretely envision their highly preferred future","Prolonged Exposure therapy systematically targeting traumatic stress and anxiety symptomatology"], answer:2, difficulty:"easy", rationale:"Correct: (C) SFBT's miracle question: 'If a miracle happened tonight and your problem was solved, how would you know? What would be different?' This helps clients envision their preferred future and identify small steps toward it.\n\nWhy others are wrong:\n(A) CBT uses thought records and behavioral experiments\n(B) Psychoanalysis uses free association and interpretation\n(D) Exposure therapy uses hierarchy-based exposure"},
        {domainId:6, q:"Trauma-Focused CBT (TF-CBT) was specifically developed for:", options:["Adult civilian populations suffering from chronic treatment-resistant post-traumatic stress disorder","Children and adolescents who have experienced significant trauma and are exhibiting related symptoms","Married couples currently struggling with severe relationship trauma or recent significant infidelity","Older adult geriatric populations dealing with complicated grief following spousal bereavement"], answer:1, difficulty:"easy", rationale:"Correct: (B) TF-CBT (Cohen, Mannarino & Deblinger) is a 12-25 session evidence-based treatment for children ages 3-18 with trauma-related symptoms. Uses PRACTICE components: Psychoeducation, Relaxation, Affect regulation, Cognitive processing, Trauma narrative, In vivo exposure, Conjoint sessions, Enhancing safety.\n\nWhy others are wrong:\n(A) Adults → PE, CPT, EMDR\n(C) Couples → EFT, Gottman\n(D) Older adults with grief → complicated grief treatment"},
        {domainId:6, q:"Transference in psychoanalytic therapy refers to:", options:["The treating therapist's unacknowledged counterproductive emotional reactions to the clinical client","The client's unconscious redirection of deeply rooted feelings from past relationships to the therapist","The administrative process of formally transferring the client to another treating psychologist","The conscious and deliberately expressed appropriate admiration the client holds for the therapist"], answer:1, difficulty:"easy", rationale:"Correct: (B) Transference: the client unconsciously projects feelings, attitudes, and expectations from past relationships onto the therapist. Analyzing transference reveals the client's relational patterns and unconscious conflicts.\n\nWhy others are wrong:\n(A) Therapist's reactions = countertransference\n(C) Transferring clients is a logistics issue, not a therapeutic concept\n(D) Transference is unconscious, not conscious admiration"},
        {domainId:6, q:"Reality therapy (Glasser) is based on:", options:["Complex foundational psychoanalytic principles investigating historical childhood emotional fixations","Choice theory positing that all human behavior is purposefully chosen to meet fundamental basic needs","Classical associative conditioning principles strictly focusing on observable stimulus-response sequences","Existential philosophical paradigms exclusively prioritizing anxiety related to the reality of mortality"], answer:1, difficulty:"medium", rationale:"Correct: (B) Glasser's Choice Theory: all behavior is purposeful and chosen to meet five basic needs — survival, love/belonging, power, freedom, and fun. Reality therapy focuses on present choices and personal responsibility.\n\nWhy others are wrong:\n(A) Reality therapy explicitly rejects psychoanalytic concepts\n(C) Classical conditioning → behavioral therapy\n(D) While sharing some existential themes, reality therapy is based on Choice Theory specifically"},
        {domainId:6, q:"In couples therapy, Gottman's research identified the 'Four Horsemen' that predict relationship failure:", options:["Severe generalized anxiety, clinical depression, unpredictable anger, and paralyzing fear","Pervasive criticism, profound contempt, chronic defensiveness, and emotional stonewalling","Generational enmeshment, emotional disengagement, systematic triangulation, and scapegoating","Psychological denial, emotional projection, ongoing displacement, and behavioral regression"], answer:1, difficulty:"medium", rationale:"Correct: (B) Gottman's Four Horsemen: Criticism (attacking character, not behavior), Contempt (disrespect, mockery — the strongest predictor of divorce), Defensiveness (counter-attacking), Stonewalling (withdrawing/shutting down).\n\nWhy others are wrong:\n(A) These are individual emotions, not relationship patterns\n(C) These are structural family therapy concepts (Minuchin)\n(D) These are psychoanalytic defense mechanisms"},
        {domainId:6, q:"Acceptance and Commitment Therapy (ACT) differs from traditional CBT primarily in that ACT:", options:["Uniquely incorporates behavioral exposure techniques into the standard psychotherapeutic protocol","Does not attempt to change thought content directly, but rather changes the relationship to the thoughts","Explicitly focuses absolutely exclusively on rapid behavior change and overt skill development","Relies almost exclusively upon concurrent pharmacological medication as the primary intervention"], answer:1, difficulty:"medium", rationale:"Correct: (B) CBT aims to change maladaptive thought content (cognitive restructuring). ACT uses cognitive defusion — changing how you RELATE to thoughts rather than their content. A thought is 'just a thought,' not reality. ACT promotes psychological flexibility through acceptance, defusion, values, and committed action.\n\nWhy others are wrong:\n(A) Both ACT and CBT can use exposure\n(C) ACT integrates acceptance AND behavior change\n(D) ACT is a psychotherapy, not pharmacotherapy"},
        {domainId:6, q:"Multisystemic Therapy (MST) was developed for:", options:["Adults suffering from treatment-resistant major depressive disorder experiencing active suicidality","Juvenile offenders displaying serious persistent antisocial behavior and significant delinquency","Couples severely struggling with communication deficits and repeated emotional infidelity issues","Elderly geriatric patients suffering from advanced stages of various neurocognitive dementias"], answer:1, difficulty:"medium", rationale:"Correct: (B) MST (Henggeler) is an intensive, home-based treatment for youth with serious antisocial behavior. It addresses multiple systems (family, school, peers, community) and has strong evidence for reducing recidivism and out-of-home placements.\n\nWhy others are wrong:\n(A) MST targets youth, not adults with depression\n(C) Couples therapy → EFT, Gottman\n(D) Dementia care involves different interventions"},

        // ===== Domain 1: Biological Bases (10) =====
        {domainId:1, q:"The substantia nigra is most associated with:", options:["Language processing comprehension and fluent phonetic expression networks","Dopamine production and the modulation of voluntary motor control","Consolidation of short-term memories into stable long-term storage","Complex visual processing and binocular depth perception synthesis"], answer:1, difficulty:"medium", rationale:"Correct: (B) The substantia nigra (part of midbrain/basal ganglia) contains dopaminergic neurons critical for motor control. Degeneration of these neurons causes Parkinson's disease's motor symptoms.\n\nWhy others are wrong:\n(A) Language → Broca's and Wernicke's areas\n(C) Memory consolidation → hippocampus\n(D) Visual processing → occipital cortex"},
        {domainId:1, q:"The anterior cingulate cortex (ACC) is primarily involved in:", options:["Primary execution of finely coordinated distal motor movements","Error detection, conflict monitoring, and emotional regulation","Early-stage processing of complex binocular visual stimuli","Comprehension of basic auditory and phonetic information"], answer:1, difficulty:"hard", rationale:"Correct: (B) The ACC monitors conflicts between competing responses, detects errors, and integrates cognitive and emotional information. Implicated in OCD (excessive error detection), depression, and pain processing.\n\nWhy others are wrong:\n(A) Motor execution → primary motor cortex\n(C) Visual processing → occipital lobe\n(D) Auditory comprehension → Wernicke's area/temporal lobe"},
        {domainId:1, q:"Norepinephrine is primarily produced in the:", options:["Raphe nuclei located broadly throughout the primary brainstem structure","Locus coeruleus situated centrally within the pontine region","Substantia nigra serving the basal ganglia motor circuitry","Nucleus accumbens functioning as the primary reward center"], answer:1, difficulty:"medium", rationale:"Correct: (B) The locus coeruleus in the pons is the primary source of norepinephrine in the brain. It projects widely and is involved in arousal, attention, stress response, and the fight-or-flight response.\n\nWhy others are wrong:\n(A) Raphe nuclei → serotonin production\n(C) Substantia nigra → dopamine production\n(D) Nucleus accumbens → receives dopamine (reward processing)"},
        {domainId:1, q:"Damage to the ventral stream ('what pathway') would impair:", options:["Spatial localization and coordinate mapping of objects","Object recognition and comprehensive visual identification","Complex sequential motor planning and execution","Expressive language production and phonetic articulation"], answer:1, difficulty:"medium", rationale:"Correct: (B) The ventral stream (occipital → temporal) processes object identity — 'what' an object is. Damage causes visual agnosia (inability to recognize objects despite intact vision).\n\nWhy others are wrong:\n(A) Spatial localization → dorsal stream ('where/how' pathway)\n(C) Motor planning → premotor cortex, supplementary motor area\n(D) Language → Broca's area"},
        {domainId:1, q:"The insula cortex has been implicated in:", options:["Exclusively coordinating distal voluntary motor functions","Interoception, disgust, empathy, and awareness of bodily states","Processing primary unrefined olfactory sensory input","Early-stage visual feature detection and integration"], answer:1, difficulty:"hard", rationale:"Correct: (B) The insula integrates interoceptive signals (awareness of internal body states), processes disgust, supports empathy, and contributes to subjective feeling states. It's implicated in addiction, anxiety, and alexithymia.\n\nWhy others are wrong:\n(A) The insula has diverse functions beyond motor\n(C) Olfaction primarily involves the olfactory bulb and piriform cortex\n(D) Visual processing → occipital lobe"},
        {domainId:1, q:"Huntington's disease is caused by:", options:["A recessive gene defect located primarily on chromosome four","An autosomal dominant gene causing degeneration of the caudate nucleus","Prolonged heavy exposure to specific environmental neurotoxic agents","Severe chronic nutritional deficiency of thiamine during development"], answer:1, difficulty:"medium", rationale:"Correct: (B) Huntington's is autosomal DOMINANT — only one copy of the gene (CAG repeat expansion on chromosome 4) is needed. It causes progressive degeneration of the caudate nucleus/striatum, producing chorea, cognitive decline, and psychiatric symptoms.\n\nWhy others are wrong:\n(A) It's dominant, not recessive\n(C) It's genetic, not environmental\n(D) Thiamine deficiency → Wernicke-Korsakoff syndrome"},
        {domainId:1, q:"Mirror neurons fire both when:", options:["An individual experiences deep delta-wave restorative sleep cycles","An organism performs an action AND observes another performing the same action","A person engages simultaneously in complex cognitive thought and speech","Only brief REM sleep periods characterized by profound muscle atonia"], answer:1, difficulty:"medium", rationale:"Correct: (B) Mirror neurons (first discovered in macaque premotor cortex by Rizzolatti) fire both during action execution and action observation. They may underlie imitation learning, empathy, and theory of mind. Mirror neuron dysfunction has been hypothesized in ASD.\n\nWhy others are wrong:\n(A) Mirror neurons are about action observation/execution, not sleep\n(C) Thinking and speaking involve different neural systems\n(D) Mirror neurons are active during waking action processing"},
        {domainId:1, q:"The ventromedial hypothalamus (VMH) is associated with:", options:["Initiating hunger and driving complex food-seeking behaviors","Satiety — significant lesions consistently cause hyperphagia (overeating)","Regulating systemic fluid balance and basic thirst mechanisms","Monitoring and adjusting core physiological body temperature"], answer:1, difficulty:"medium", rationale:"Correct: (B) The VMH functions as a 'satiety center.' Lesions of the VMH cause hyperphagia (overeating) and obesity because the signal to stop eating is lost. The lateral hypothalamus (LH) serves as the 'hunger center.'\n\nWhy others are wrong:\n(A) Hunger initiation → lateral hypothalamus\n(C) Thirst → involves subfornical organ and other hypothalamic areas\n(D) Temperature regulation involves the anterior hypothalamus"},
        {domainId:1, q:"Neurogenesis in the adult human brain primarily occurs in:", options:["Broad overlapping regions spanning the entire cerebral cortex","The subgranular zone of the hippocampus and the olfactory bulb","Deep interconnected structures exclusively within the cerebellum","The upper cervical segments of the central spinal cord"], answer:1, difficulty:"hard", rationale:"Correct: (B) Adult neurogenesis is largely limited to two regions: the subgranular zone of the hippocampal dentate gyrus (important for learning/memory) and the subventricular zone/olfactory bulb. This challenges the old doctrine that adult brains cannot produce new neurons.\n\nWhy others are wrong:\n(A) Neurogenesis does not occur throughout the cortex in adults\n(C) Cerebellum is not a primary neurogenesis site\n(D) Spinal cord neurogenesis is extremely limited"},
        {domainId:1, q:"The difference between agonists and antagonists is:", options:["Agonists functionally block receptors while antagonists actively stimulate them","Agonists activate or enhance receptor activity; antagonists block or inhibit receptor activity","They describe exactly identical physiological receptor-binding processes","Agonists strictly apply to hormones while antagonists apply exclusively to neurotransmitters"], answer:1, difficulty:"easy", rationale:"Correct: (B) Agonists bind to receptors and activate them (mimicking the endogenous neurotransmitter). Antagonists bind to receptors and block activation (preventing the neurotransmitter from acting). Example: morphine is an opioid agonist; naloxone is an opioid antagonist.\n\nWhy others are wrong:\n(A) This reverses the definitions\n(C) They have opposite effects\n(D) Both terms apply to any receptor-ligand system"},

        // ===== Domains 2-4 (15 each split) =====
        // Domain 2: Cognitive-Affective (10)
        {domainId:2, q:"The spacing effect demonstrates that:", options:["Massed practice is always superior for immediate short-term declarative memory acquisition","Distributed practice (spacing study sessions) produces better long-term retention than massed practice","Only brief contiguous study sessions are effective for establishing durable procedural skills","Spacing only works effectively for motor skills requiring procedural memory consolidation"], answer:1, difficulty:"easy", rationale:"Correct: (B) The spacing effect (Ebbinghaus): spreading study across multiple sessions produces stronger, more durable memories than cramming. Each retrieval during spaced practice strengthens the memory trace and creates more retrieval routes.\n\nWhy others are wrong:\n(A) Cramming produces short-term gains but poor long-term retention\n(C) Session length matters less than distribution over time\n(D) Spacing benefits all types of learning — verbal, conceptual, motor"},
        {domainId:2, q:"The Stroop effect demonstrates:", options:["Inherent limitations in parallel cognitive processing capacity during complex multitasking","Automatic processing interfering with sustained controlled cognitive processing task demands","Natural memory decay and degradation over extended periods of neural inactivity","The sequential serial position effect during immediate free recall memory tasks"], answer:1, difficulty:"easy", rationale:"Correct: (B) The Stroop effect: naming the ink color of color words (e.g., 'RED' in blue ink) is slower because reading is automatic and interferes with the controlled task of color naming. Demonstrates the difficulty of inhibiting automatic processes.\n\nWhy others are wrong:\n(A) The Stroop effect is about automatic vs. controlled processing, not parallel processing\n(C) Memory decay → Ebbinghaus forgetting curve\n(D) Serial position → primacy/recency effects in list recall"},
        {domainId:2, q:"Confirmation bias is the tendency to:", options:["Objectively change core beliefs whenever presented with explicitly contradictory factual evidence","Seek, interpret, and remember information that specifically confirms preexisting beliefs","Equally and rationally weigh both confirming and disconfirming empirical evidence","Aggressively reject all new incoming information regardless of its underlying source"], answer:1, difficulty:"easy", rationale:"Correct: (B) Confirmation bias: selectively attending to information that supports preexisting beliefs while ignoring or discounting contradictory evidence. This affects clinical judgment, diagnosis, and scientific reasoning.\n\nWhy others are wrong:\n(A) Confirmation bias RESISTS belief change\n(C) The bias specifically involves UNEQUAL weighting favoring confirming evidence\n(D) New information is processed, but selectively filtered"},
        {domainId:2, q:"The Zeigarnik effect refers to:", options:["Significantly better memory retrieval for successfully completed cognitive tasks","Better memory for incomplete or interrupted tasks compared to completed ones","Rapid forgetting of information due to proactive or retroactive cognitive interference","Global memory improvement exclusively following restorative slow-wave sleep cycles"], answer:1, difficulty:"medium", rationale:"Correct: (B) Zeigarnik (1927): interrupted or incomplete tasks are better remembered than completed ones. The tension of incompletion maintains cognitive engagement. Applied in cliffhangers, study strategies, and understanding intrusive thoughts in OCD.\n\nWhy others are wrong:\n(A) Completed tasks are actually remembered WORSE (the tension is resolved)\n(C) Interference → proactive/retroactive interference\n(D) Sleep-dependent memory consolidation is a different phenomenon"},
        {domainId:2, q:"Anchoring bias in clinical judgment occurs when:", options:["Clinicians completely ignore all available diagnostic information and context","Initial information disproportionately influences all subsequent clinical judgments","Clinicians change their primary psychiatric diagnoses too frequently over time","All cognitive biases are successfully eliminated through rigorous clinical training"], answer:1, difficulty:"medium", rationale:"Correct: (B) Anchoring: the first information received (the 'anchor') has disproportionate influence on subsequent judgments. A clinician who reads a referral diagnosis before assessment may be biased toward confirming that initial diagnosis.\n\nWhy others are wrong:\n(A) Anchoring involves overweighting specific information, not ignoring all\n(C) Anchoring actually makes clinicians RESISTANT to changing initial impressions\n(D) Training can reduce but not eliminate cognitive biases"},

        // Domain 3: Social & Cultural (5)
        {domainId:3, q:"The actor-observer bias refers to:", options:["Actors attributing their own behavior to situational factors while observers attribute it to dispositional factors","Everyone within a shared cultural context making exactly the same fundamental attributional errors","Only active situational actors making consistent systematic errors in interpersonal judgment","Only passive objective observers making consistent systematic errors in interpersonal judgment"], answer:0, difficulty:"medium", rationale:"Correct: (A) The actor-observer asymmetry: when explaining OUR behavior, we emphasize situations ('I was stressed'). When explaining OTHERS' behavior, we emphasize dispositions ('they're lazy'). This relates to different information available — actors see their varying situations; observers see consistent behavior.\n\nWhy others are wrong:\n(B) The whole point is that actors and observers make DIFFERENT attributions\n(C)/(D) Both actors and observers show biases, just in opposite directions"},
        {domainId:3, q:"Group polarization refers to:", options:["Groups becoming significantly more moderate and compromised through structural discussion","Groups making more extreme decisions than individual members would initially make alone","Groups always fundamentally disagreeing and fracturing during complex decision processes","Perfectly equal opinion distribution emerging organically within cohesive team structures"], answer:1, difficulty:"medium", rationale:"Correct: (B) Group polarization: group discussion causes members to adopt more extreme positions in the direction they were already leaning. If individuals lean cautious → group becomes more cautious. If individuals lean risky → 'risky shift.' Mechanisms: persuasive arguments and social comparison.\n\nWhy others are wrong:\n(A) Groups become MORE extreme, not more moderate\n(C) Polarization occurs within like-minded groups, not through disagreement\n(D) Opinions converge toward a more extreme average, not distribute equally"},
        {domainId:3, q:"Heuristic processing (peripheral route in ELM) is most likely when:", options:["The target audience is highly motivated and fully able to consciously process the message","The audience has overall low motivation or specific limited ability to think carefully about the message","The persuasive message simultaneously contains incredibly strong logical empirical arguments","The target audience is already an established knowledgeable expert on the specific topic"], answer:1, difficulty:"medium", rationale:"Correct: (B) ELM's peripheral route: when motivation or ability to process is low, people rely on heuristic cues — source attractiveness, number of arguments, emotional appeals — rather than evaluating argument quality. Attitude change is less durable.\n\nWhy others are wrong:\n(A) High motivation + ability → central route processing\n(C) Strong arguments matter for central route processing\n(D) Experts typically use central route (they have knowledge to evaluate arguments)"},
        {domainId:3, q:"Obedience in Milgram's experiments was DECREASED by:", options:["Having the primary authority figure remaining physically present in the laboratory room","Increasing the physical/psychological distance between the participant and the authority figure","Significantly making the participant the absolutely only one available for the experiment","Removing any other confederate participants who were present during the initial procedures"], answer:1, difficulty:"medium", rationale:"Correct: (B) Milgram's variations showed obedience decreased when: authority was remote (telephone instructions), the victim was closer (touch proximity), another 'participant' defied the authority, or the experiment was in a less prestigious setting.\n\nWhy others are wrong:\n(A) Authority presence INCREASED obedience\n(C) Being the only one available didn't specifically decrease obedience\n(D) Confederates who defied authority decreased obedience"},
        {domainId:3, q:"Social loafing is LEAST likely when:", options:["The collaborative group is exceptionally large and highly completely anonymous","Specific individual task contributions remain totally completely unidentifiable","The collaborative task is personally meaningful and individual contributions are clearly identifiable","The established collaborative group displays exceptionally low internal social cohesion"], answer:2, difficulty:"easy", rationale:"Correct: (C) Social loafing decreases when: individual efforts are identifiable, the task is meaningful/engaging, the group is cohesive, and individual performance is evaluated. Karau & Williams' collective effort model: people exert effort when they expect their contribution to be instrumental.\n\nWhy others are wrong:\n(A) Large anonymous groups INCREASE social loafing\n(B) Unidentifiable contributions INCREASE loafing\n(D) Low cohesion doesn't specifically reduce loafing"},

        // Domain 4: Development (5)
        {domainId:4, q:"In Piaget's theory, 'accommodation' refers to:", options:["Seamlessly fitting completely new information into preexisting established schemas","Modifying existing cognitive schemas or creating new ones to incorporate novel information","Actively ignoring contradictory environmental information to preserve established structures","Passively memorizing sequential new facts without engaging deeper schematic processes"], answer:1, difficulty:"easy", rationale:"Correct: (B) Accommodation: modifying existing cognitive schemas or creating new ones to incorporate information that doesn't fit existing frameworks. Complementary to assimilation (fitting new info into existing schemas). Together they drive cognitive development.\n\nWhy others are wrong:\n(A) Fitting into existing schemas = assimilation\n(C) Ignoring contradictory information = not a Piagetian concept (closer to confirmation bias)\n(D) Simple memorization doesn't describe schema modification"},
        {domainId:4, q:"Kohlberg's Stage 4 (Law and Order) moral reasoning is characterized by:", options:["Strictly avoiding punishment and deferring entirely to completely unyielding power","Actively gaining broader social approval through conforming to established interpersonal norms","Maintaining overarching social order through explicitly following rules and respecting authority","Acting exclusively on universal abstract ethical principles regardless of existing legal codes"], answer:2, difficulty:"easy", rationale:"Correct: (C) Stage 4 (Conventional level): morality is about maintaining social order, respecting laws, and fulfilling duties. Rules exist for the good of society. Breaking rules threatens social stability.\n\nWhy others are wrong:\n(A) Avoiding punishment = Stage 1 (Preconventional)\n(B) Gaining social approval = Stage 3 ('Good boy/nice girl')\n(D) Universal principles = Stage 6 (Postconventional)"},
        {domainId:4, q:"Erikson's 'Intimacy vs. Isolation' stage occurs during:", options:["Adolescence exclusively dealing with fundamental identity role formation processes","Young adulthood (approximately 18-40) focusing directly on building close commitments","Middle adulthood centrally prioritizing lasting external career and familial generativity","Late adulthood actively evaluating past life events aiming predominantly toward integrity"], answer:1, difficulty:"easy", rationale:"Correct: (B) Intimacy vs. Isolation (young adulthood): developing close, committed relationships. Successful resolution → capacity for love. Unsuccessful → loneliness and isolation. Builds on successful identity formation in adolescence.\n\nWhy others are wrong:\n(A) Adolescence = Identity vs. Role Confusion\n(C) Middle adulthood = Generativity vs. Stagnation\n(D) Late adulthood = Integrity vs. Despair"},
        {domainId:4, q:"Object permanence, according to Piaget, is fully developed by approximately:", options:["4 months of early infant physiological and perceptual cognitive development","8-12 months during the initial transitional stages of active motor exploration","18-24 months when the maturing child can effectively mentally represent object displacements","3 years during the fully established early preoperational cognitive developmental phase"], answer:2, difficulty:"medium", rationale:"Correct: (C) While object permanence begins emerging around 8 months (A-not-B error phase), it is fully developed by 18-24 months when the child can represent invisible displacements — understanding that objects exist independently even when moved out of sight multiple times.\n\nWhy others are wrong:\n(A) 4 months — too early; infants haven't developed this concept\n(B) 8-12 months — object permanence is emerging but not fully developed (A-not-B errors)\n(D) 3 years — by this age, children are in the preoperational stage with full object permanence"},
        {domainId:4, q:"Permissive parenting (Baumrind) is characterized by:", options:["Consistently high warmth integrated tightly with rigorous high behavioral control","High emotional warmth but characteristically low structural control and demands","Characteristically low emotional warmth paired directly with rigorous high behavioral control","Characteristically low emotional warmth paired concurrently with low behavioral control"], answer:1, difficulty:"easy", rationale:"Correct: (B) Permissive parents are warm, accepting, and responsive but set few limits or demands. Children may have difficulty with self-regulation, authority, and impulse control.\n\nWhy others are wrong:\n(A) High warmth + high control = authoritative (optimal)\n(C) Low warmth + high control = authoritarian\n(D) Low warmth + low control = neglectful/uninvolved"}
    ];

    batch39.forEach(q => {
        const domain = EPPPData.domains.find(d => d.id === q.domainId);
        if (domain) {
            domain.questions.push({
                q: q.q, options: q.options, answer: q.answer,
                difficulty: q.difficulty, rationale: q.rationale,
                domainId: q.domainId, domainName: domain.name
            });
        }
    });

    console.log(`PasstheEPPP: Loaded ${batch39.length} additional questions (batch 39).`);
})();
